import { NextRequest, NextResponse } from "next/server";
import { r2StreamFile, r2GetMetadata, generateETag, isCached } from "@/lib/r2";
import { requirePartAccess, extractPartNumberFromR2Key } from "@/lib/part-access";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const MIME_TYPES: Record<string, string> = {
  ".mp4": "video/mp4",
  ".wav": "audio/wav",
  ".mp3": "audio/mpeg",
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".webp": "image/webp",
  ".gif": "image/gif",
  ".pdf": "application/pdf",
  ".txt": "text/plain",
  ".json": "application/json",
};

function getMimeType(key: string): string {
  const ext = key.substring(key.lastIndexOf(".")).toLowerCase();
  return MIME_TYPES[ext] || "application/octet-stream";
}

export async function GET(req: NextRequest) {
  const { searchParams } = req.nextUrl;
  const key = searchParams.get("key");

  if (!key) {
    return new NextResponse("Missing key parameter", { status: 400 });
  }

  // Access control: extract part number from key and enforce paid-content rules.
  // Key format examples: "videos/Part 50.mp4", "audio/Part 1.mp3", "mindmaps/Part 3 - Mindmap.png"
  const partNum = extractPartNumberFromR2Key(key);

  if (partNum !== null) {
    const deny = await requirePartAccess(partNum);
    if (deny) return deny;
  } else {
    // Key does not match a known part — deny by default to avoid arbitrary R2 access.
    return new NextResponse("Forbidden", { status: 403 });
  }

  try {
    const metadata = await r2GetMetadata(key);

    if (!metadata) {
      return new NextResponse("Not found", { status: 404 });
    }

    const etag = generateETag({ size: metadata.size, lastModified: metadata.lastModified });
    const clientETag = req.headers.get("if-none-match");

    if (isCached(etag, clientETag)) {
      return new NextResponse(null, { status: 304 });
    }

    const rangeHeader = req.headers.get("range");
    const contentType = getMimeType(key);

    if (rangeHeader && (contentType.startsWith("video/") || contentType.startsWith("audio/"))) {
      return await handleRangeRequest(key, rangeHeader, metadata, contentType, etag);
    }

    const response = await r2StreamFile(key);

    if (!response.Body) {
      return new NextResponse("Error reading file", { status: 500 });
    }

    const stream = response.Body.transformToWebStream();

    return new NextResponse(stream as any, {
      status: 200,
      headers: {
        "Content-Type": contentType,
        "Content-Length": String(metadata.size),
        "Cache-Control": "private, max-age=3600",
        "ETag": etag,
        "Accept-Ranges": "bytes",
      },
    });
  } catch (error) {
    console.error("Error streaming from R2:", error);
    return new NextResponse("Internal server error", { status: 500 });
  }
}

async function handleRangeRequest(
  key: string,
  rangeHeader: string,
  metadata: { size: number; lastModified?: Date },
  contentType: string,
  etag: string
) {
  const fileSize = metadata.size;
  const match = /bytes=(\d+)-(\d*)/.exec(rangeHeader);

  if (!match) {
    return new NextResponse("Invalid range", { status: 416 });
  }

  const start = parseInt(match[1], 10);
  const end = match[2] ? parseInt(match[2], 10) : fileSize - 1;

  if (start >= fileSize || end >= fileSize || start > end) {
    return new NextResponse("Range not satisfiable", {
      status: 416,
      headers: { "Content-Range": `bytes */${fileSize}` },
    });
  }

  const chunkSize = end - start + 1;

  try {
    const response = await r2StreamFile(key, `bytes=${start}-${end}`);

    if (!response.Body) {
      return new NextResponse("Error reading file", { status: 500 });
    }

    const stream = response.Body.transformToWebStream();

    return new NextResponse(stream as any, {
      status: 206,
      headers: {
        "Content-Type": contentType,
        "Content-Range": `bytes ${start}-${end}/${fileSize}`,
        "Accept-Ranges": "bytes",
        "Content-Length": String(chunkSize),
        "Cache-Control": "private, max-age=3600",
        "ETag": etag,
      },
    });
  } catch (error) {
    console.error("Error streaming range from R2:", error);
    return new NextResponse("Internal server error", { status: 500 });
  }
}

﻿"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { loadStripe } from "@stripe/stripe-js";
import { Elements, PaymentElement, useStripe, useElements } from "@stripe/react-stripe-js";
import { Check, Lock, Users, ArrowLeft, Shield, Star, RefreshCw, ArrowUpCircle, Tag, X } from "lucide-react";
import Link from "next/link";
import { PLANS, formatPrice } from "@/lib/stripe-config";

const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!);

const LIFETIME_PLAN  = PLANS.family;
const MONTHLY_PLAN   = PLANS.familyMonthly;

type BillingCycle = "lifetime" | "monthly";

// ── Stripe payment form ───────────────────────────────────────

function FamilyCheckoutForm({
  cycle,
  isUpgrade,
  finalPrice,
}: {
  cycle: BillingCycle;
  isUpgrade: boolean;
  finalPrice: number;
}) {
  const stripe   = useStripe();
  const elements = useElements();
  const [error, setError]           = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);

  const label = isUpgrade
    ? `Upgrade to Family Lifetime — ${formatPrice(finalPrice)}`
    : cycle === "lifetime"
    ? `Get Family Access — ${formatPrice(finalPrice)}`
    : `Subscribe — ${formatPrice(finalPrice)}/mo`;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setProcessing(true);
    setError(null);

    const { error: submitError } = await elements.submit();
    if (submitError) {
      setError(submitError.message ?? "An error occurred");
      setProcessing(false);
      return;
    }

    // Family Lifetime is a one-time PaymentIntent — use ?type=family so the success
    // page calls verify-payment, which also sets planType=family on the user.
    // Family Monthly is a subscription — use ?type=family-subscription so the success
    // page polls /api/stripe/check-access AND shows the family profile-setup CTA.
    const returnUrl = cycle === "lifetime"
      ? `${window.location.origin}/payment/success?type=family`
      : `${window.location.origin}/payment/success?type=family-subscription`;

    const { error: confirmError } = await stripe.confirmPayment({
      elements,
      confirmParams: { return_url: returnUrl },
    });

    if (confirmError) {
      setError(confirmError.message ?? "Payment failed. Please try again.");
      setProcessing(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      <PaymentElement options={{ wallets: { link: "never" } }} />

      {error && (
        <div className="p-4 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
          {error}
        </div>
      )}

      <button
        type="submit"
        disabled={!stripe || processing}
        className="w-full flex items-center justify-center gap-2 px-6 py-4 rounded-xl bg-gold hover:bg-gold-light disabled:opacity-60 text-ink font-bold text-base transition-colors shadow-lg shadow-gold/20"
      >
        <Lock className="w-4 h-4" />
        {processing ? "Processing…" : label}
      </button>

      <p className="text-xs text-zinc-500 text-center">
        Secure payment powered by Stripe · Your information is encrypted
      </p>
      <p className="text-xs text-zinc-600 text-center leading-relaxed">
        By purchasing you agree to our{" "}
        <a href="/terms" className="underline hover:text-zinc-400 transition-colors">Terms of Service</a>
        {", "}
        <a href="/privacy" className="underline hover:text-zinc-400 transition-colors">Privacy Policy</a>
        {", and "}
        <a href="/refund" className="underline hover:text-zinc-400 transition-colors">Refund Policy</a>.
      </p>
    </form>
  );
}

// ── Main checkout page ────────────────────────────────────────

interface FamilyCheckoutClientProps {
  userEmail: string;
  userName: string;
  initialCycle?: BillingCycle;
  isUpgradeFromLifetime?: boolean;
}

export default function FamilyCheckoutClient({
  userEmail,
  initialCycle = "lifetime",
  isUpgradeFromLifetime = false,
}: FamilyCheckoutClientProps) {
  const router = useRouter();

  // Upgraders from Individual Lifetime can only go to Family Lifetime — lock the cycle.
  const [cycle, setCycle] = useState<BillingCycle>(
    isUpgradeFromLifetime ? "lifetime" : initialCycle
  );
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [hasActiveSub, setHasActiveSub] = useState(false);

  // Pricing state
  const [basePrice, setBasePrice] = useState<number>(
    isUpgradeFromLifetime
      ? LIFETIME_PLAN.upgradeFromLifetimePrice
      : LIFETIME_PLAN.price
  );
  const [finalPrice, setFinalPrice] = useState<number>(basePrice);
  const [discountAmount, setDiscountAmount] = useState(0);

  // Coupon
  const [couponInput, setCouponInput] = useState("");
  const [couponLoading, setCouponLoading] = useState(false);
  const [couponError, setCouponError] = useState<string | null>(null);
  const [appliedCoupon, setAppliedCoupon] = useState<{
    code: string;
    label: string;
    discount: number;
    finalPrice: number;
  } | null>(null);

  // Free access
  const [freeAccess, setFreeAccess] = useState(false);
  const [freeClaimLoading, setFreeClaimLoading] = useState(false);
  const [freeClaimError, setFreeClaimError] = useState<string | null>(null);

  const isUpgrade = isUpgradeFromLifetime;

  // ── Create intent ────────────────────────────────────────────────────────

  const createIntent = async (
    currentCycle: BillingCycle,
    promoCode?: string
  ): Promise<{ discountAmount: number; finalPrice: number } | null> => {
    setLoading(true);
    setClientSecret(null);
    setFreeAccess(false);
    setError(null);

    const endpoint =
      currentCycle === "lifetime"
        ? "/api/stripe/create-family-payment-intent"
        : "/api/stripe/create-family-subscription-intent";

    try {
      const r = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isUpgrade, promoCode }),
      });
      const data = await r.json();

      if (data.error) {
        if (data.hasActiveSubscription) {
          setHasActiveSub(true);
        } else {
          setError(data.error);
        }
        return null;
      }

      const discount: number = data.promoDiscountAmount ?? 0;
      const price: number = data.finalAmount ?? basePrice;

      if (data.baseAmount) setBasePrice(data.baseAmount);
      setFinalPrice(price);
      setDiscountAmount(discount);

      if (data.freeAccess) {
        setFreeAccess(true);
      } else {
        setClientSecret(data.clientSecret);
      }
      return { discountAmount: discount, finalPrice: price };
    } catch {
      setError("Failed to initialize checkout. Please refresh the page.");
      return null;
    } finally {
      setLoading(false);
    }
  };

  // Re-fetch whenever billing cycle changes
  useEffect(() => {
    createIntent(cycle, appliedCoupon?.code);
    // Intentionally excludes appliedCoupon — we only re-run when cycle changes,
    // passing the current coupon value at call time.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cycle]);

  // ── Coupon handlers ──────────────────────────────────────────────────────

  const handleApplyCoupon = async () => {
    const code = couponInput.trim();
    if (!code) return;
    setCouponLoading(true);
    setCouponError(null);

    try {
      const result = await createIntent(cycle, code);
      if (result) {
        setAppliedCoupon({
          code: code.toUpperCase(),
          label: "Promo applied",
          discount: result.discountAmount,
          finalPrice: result.finalPrice,
        });
      } else {
        setCouponError("Invalid promo code");
      }
    } catch {
      setCouponError("Could not apply code. Please try again.");
    } finally {
      setCouponLoading(false);
    }
  };

  const handleRemoveCoupon = () => {
    setAppliedCoupon(null);
    setCouponInput("");
    setCouponError(null);
    createIntent(cycle);
  };

  // ── Free access claim ────────────────────────────────────────────────────

  const handleClaimFreeAccess = async () => {
    const code = appliedCoupon?.code ?? couponInput.trim();
    if (!code) return;
    setFreeClaimLoading(true);
    setFreeClaimError(null);
    try {
      const res = await fetch("/api/stripe/claim-free-access", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ promoCode: code, planType: "family" }),
      });
      const data = await res.json();
      if (!res.ok) {
        setFreeClaimError(data.error || "Something went wrong");
        return;
      }
      router.push("/my-courses");
    } catch {
      setFreeClaimError("Something went wrong. Please try again.");
    } finally {
      setFreeClaimLoading(false);
    }
  };

  // ── Derived display values ────────────────────────────────────────────────

  const activeFeatures =
    cycle === "lifetime" ? LIFETIME_PLAN.features : MONTHLY_PLAN.features;
  const displayPrice = appliedCoupon ? appliedCoupon.finalPrice : finalPrice;
  const displayDiscount = appliedCoupon ? appliedCoupon.discount : discountAmount;

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col lg:flex-row">
      {/* ── Left column — plan details ─────────────────────────────────────── */}
      <div className="lg:w-1/2 bg-zinc-900/50 border-r border-zinc-800 px-6 sm:px-12 py-12 flex flex-col justify-center">
        <Link
          href="/billing"
          className="inline-flex items-center gap-2 text-sm text-zinc-500 hover:text-zinc-300 transition-colors mb-10"
        >
          <ArrowLeft className="w-4 h-4" />
          Back to billing
        </Link>

        {/* Plan badge */}
        <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-gold/10 border border-gold/25 text-gold text-xs font-semibold mb-5 w-fit">
          <Users className="w-3.5 h-3.5" />
          Family Access
        </div>

        <h1 className="text-3xl sm:text-4xl font-bold text-white mb-3">
          Complete Seerah
          <br />
          <span className="text-gold">Family Access</span>
        </h1>

        <p className="text-zinc-400 text-base mb-8 leading-relaxed">
          One household account with up to 5 learner profiles. Parents log in
          once, create profiles for each family member, and each learner gets
          their own separate progress for all course assets.
        </p>

        {/* Billing cycle toggle — hidden for upgraders (lifetime-only path) */}
        {!isUpgrade && (
          <div className="flex items-center gap-1 bg-zinc-800 rounded-xl p-1 w-fit mb-8">
            <button
              onClick={() => setCycle("lifetime")}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                cycle === "lifetime"
                  ? "bg-gold text-black shadow"
                  : "text-zinc-400 hover:text-zinc-200"
              }`}
            >
              <Star className="w-3.5 h-3.5 inline mr-1.5" />
              Lifetime — {formatPrice(LIFETIME_PLAN.price)}
            </button>
            <button
              onClick={() => setCycle("monthly")}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                cycle === "monthly"
                  ? "bg-gold text-black shadow"
                  : "text-zinc-400 hover:text-zinc-200"
              }`}
            >
              <RefreshCw className="w-3.5 h-3.5 inline mr-1.5" />
              Monthly — {formatPrice(MONTHLY_PLAN.price)}/mo
            </button>
          </div>
        )}

        {/* Price display */}
        <div className="mb-8">
          {isUpgrade ? (
            <div>
              <div className="flex items-baseline gap-3">
                <span className="text-4xl font-bold text-white">
                  {formatPrice(LIFETIME_PLAN.upgradeFromLifetimePrice)}
                </span>
                <span className="text-zinc-500 text-sm line-through">
                  {formatPrice(LIFETIME_PLAN.price)}
                </span>
                <span className="text-zinc-500 text-sm">one-time</span>
              </div>
              <p className="text-xs text-gold/80 mt-2 flex items-center gap-1.5">
                <ArrowUpCircle className="w-3.5 h-3.5 flex-shrink-0" />
                You&apos;ve already paid $99 for Individual Lifetime — you&apos;re
                only paying the $100 difference.
              </p>
            </div>
          ) : cycle === "lifetime" ? (
            <div>
              <div className="flex items-baseline gap-2">
                <span className="text-4xl font-bold text-white">
                  {formatPrice(LIFETIME_PLAN.price)}
                </span>
                <span className="text-zinc-500 text-sm">
                  one-time · lifetime access
                </span>
              </div>
              <p className="text-xs text-zinc-600 mt-1">
                Pay once, access forever.
              </p>
            </div>
          ) : (
            <div>
              <div className="flex items-baseline gap-2">
                <span className="text-4xl font-bold text-white">
                  {formatPrice(MONTHLY_PLAN.price)}
                </span>
                <span className="text-zinc-500 text-sm">
                  / month · cancel anytime
                </span>
              </div>
              <p className="text-xs text-zinc-600 mt-1">
                Full family access while subscribed.{" "}
                <span className="text-gold-dim/70">
                  Upgrade to lifetime anytime for {formatPrice(LIFETIME_PLAN.price)}.
                </span>
              </p>
            </div>
          )}
        </div>

        {/* Feature list */}
        <ul className="space-y-3">
          {activeFeatures.map((feature) => (
            <li key={feature} className="flex items-start gap-3">
              <div className="w-5 h-5 rounded-full bg-gold/15 flex items-center justify-center flex-shrink-0 mt-0.5">
                <Check className="w-3 h-3 text-gold" />
              </div>
              <span className="text-sm text-zinc-300">{feature}</span>
            </li>
          ))}
        </ul>

        {/* Trust badges */}
        <div className="mt-8 pt-6 border-t border-zinc-800 flex flex-wrap gap-4">
          <div className="flex items-center gap-2 text-xs text-zinc-500">
            <Shield className="w-4 h-4 text-zinc-600" />
            7-day refund guarantee
          </div>
          <div className="flex items-center gap-2 text-xs text-zinc-500">
            <Lock className="w-4 h-4 text-zinc-600" />
            Secure payment
          </div>
          {cycle === "lifetime" && (
            <div className="flex items-center gap-2 text-xs text-zinc-500">
              <Star className="w-4 h-4 text-zinc-600" />
              Lifetime access
            </div>
          )}
          {cycle === "monthly" && (
            <div className="flex items-center gap-2 text-xs text-zinc-500">
              <RefreshCw className="w-4 h-4 text-zinc-600" />
              Cancel anytime
            </div>
          )}
        </div>
      </div>

      {/* ── Right column — order summary + payment ──────────────────────────── */}
      <div className="lg:w-1/2 px-6 sm:px-12 py-12 flex flex-col justify-center">
        <div className="max-w-md w-full mx-auto">
          <h2 className="text-xl font-bold text-white mb-1">
            Complete your order
          </h2>
          <p className="text-sm text-zinc-500 mb-7">
            Purchasing as <span className="text-zinc-300">{userEmail}</span>
          </p>

          {/* Order summary */}
          <div className="bg-zinc-900 border border-zinc-800 rounded-xl p-4 mb-6 space-y-3">
            <div className="flex items-start justify-between">
              <div>
                <p className="text-sm font-semibold text-white">
                  {isUpgrade
                    ? "Family Lifetime (Upgrade)"
                    : cycle === "lifetime"
                    ? LIFETIME_PLAN.name
                    : MONTHLY_PLAN.name}
                </p>
                <p className="text-xs text-zinc-500 mt-0.5">
                  Up to 5 learner profiles ·{" "}
                  {isUpgrade || cycle === "lifetime"
                    ? "Lifetime access"
                    : "Cancel anytime"}
                </p>
              </div>
              <div className="text-right ml-4">
                {isUpgrade ? (
                  <>
                    <p className="text-sm font-bold text-white">
                      {formatPrice(LIFETIME_PLAN.upgradeFromLifetimePrice)}
                    </p>
                    <p className="text-xs text-zinc-600 line-through">
                      {formatPrice(LIFETIME_PLAN.price)}
                    </p>
                  </>
                ) : (
                  <p className="text-sm font-bold text-white">
                    {cycle === "lifetime"
                      ? formatPrice(LIFETIME_PLAN.price)
                      : `${formatPrice(MONTHLY_PLAN.price)}/mo`}
                  </p>
                )}
              </div>
            </div>

            {isUpgrade && (
              <div className="pt-2 border-t border-zinc-800 text-xs text-zinc-500 flex items-center justify-between">
                <span>Individual Lifetime (already paid)</span>
                <span>$99</span>
              </div>
            )}

            {/* Discount row */}
            {displayDiscount > 0 && (
              <div className="flex items-center justify-between text-sm pt-1 border-t border-zinc-800">
                <span className="text-green-400 flex items-center gap-1.5">
                  <Tag className="w-3.5 h-3.5" />
                  {appliedCoupon?.code ?? "Promo"} discount
                </span>
                <span className="text-green-400 font-medium">
                  −{formatPrice(displayDiscount)}
                </span>
              </div>
            )}

            {/* Total */}
            {cycle === "lifetime" && (
              <div className="flex items-center justify-between pt-2 border-t border-zinc-800">
                <span className="text-sm font-semibold text-white">Total</span>
                <span className="text-lg font-bold text-gold">
                  {formatPrice(displayPrice)}
                </span>
              </div>
            )}
          </div>

          {/* Coupon input — lifetime only */}
          {cycle === "lifetime" && (
            <div className="mb-6">
              {appliedCoupon ? (
                <div className="flex items-center justify-between px-3.5 py-2.5 rounded-xl bg-green-500/10 border border-green-500/20">
                  <div className="flex items-center gap-2 text-green-400 text-sm">
                    <Tag className="w-3.5 h-3.5 flex-shrink-0" />
                    <span className="font-medium">{appliedCoupon.code}</span>
                    <span className="text-green-400/60 text-xs">
                      {appliedCoupon.label}
                    </span>
                  </div>
                  <button
                    onClick={handleRemoveCoupon}
                    className="text-green-400/60 hover:text-green-400 transition-colors ml-2"
                    aria-label="Remove promo code"
                  >
                    <X className="w-3.5 h-3.5" />
                  </button>
                </div>
              ) : (
                <div className="space-y-1.5">
                  <div className="flex gap-2">
                    <input
                      type="text"
                      value={couponInput}
                      onChange={(e) => {
                        setCouponInput(e.target.value.toUpperCase());
                        setCouponError(null);
                      }}
                      onKeyDown={(e) =>
                        e.key === "Enter" && handleApplyCoupon()
                      }
                      placeholder="Promo code"
                      className="flex-1 px-3.5 py-2.5 text-sm rounded-xl border border-zinc-700 bg-zinc-900 text-white placeholder-zinc-500 focus:outline-none focus:border-gold/50 transition-colors uppercase"
                    />
                    <button
                      onClick={handleApplyCoupon}
                      disabled={couponLoading || !couponInput.trim()}
                      className="px-4 py-2.5 text-sm font-medium rounded-xl border border-zinc-700 bg-zinc-800 text-zinc-300 hover:border-gold/40 hover:text-gold transition-colors disabled:opacity-40 whitespace-nowrap"
                    >
                      {couponLoading ? "…" : "Apply"}
                    </button>
                  </div>
                  {couponError && (
                    <p className="text-xs text-red-400">{couponError}</p>
                  )}
                </div>
              )}
            </div>
          )}

          {/* Loading spinner */}
          {loading && (
            <div className="flex items-center justify-center py-12">
              <div className="w-8 h-8 border-2 border-gold/30 border-t-gold rounded-full animate-spin" />
            </div>
          )}

          {/* Already subscribed — billing link */}
          {hasActiveSub && !loading && (
            <div className="p-5 rounded-xl bg-gold/10 border border-gold/25 text-center space-y-4">
              <p className="text-sm font-semibold text-white">
                You already have an active monthly subscription.
              </p>
              <p className="text-xs text-zinc-400">
                You cannot start a second subscription while one is active.
              </p>
              <a
                href="/billing"
                className="inline-flex items-center gap-2 px-5 py-3 rounded-xl bg-gold hover:bg-gold-light text-ink font-bold text-sm transition-colors"
              >
                Manage your subscription
              </a>
            </div>
          )}

          {/* Error */}
          {error && !loading && (
            <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm mb-4">
              {error}
            </div>
          )}

          {/* Free access claim */}
          {freeAccess && !loading && (
            <div className="space-y-4">
              <div className="p-5 rounded-xl bg-gold/10 border border-gold/25 text-center">
                <div className="text-3xl mb-3">🎁</div>
                <h3 className="text-lg font-bold text-white mb-1">
                  Free Access Applied
                </h3>
                <p className="text-zinc-400 text-sm">
                  Your promo code gives you full family access at no charge.
                </p>
              </div>
              {freeClaimError && (
                <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                  {freeClaimError}
                </div>
              )}
              <button
                onClick={handleClaimFreeAccess}
                disabled={freeClaimLoading}
                className="w-full flex items-center justify-center gap-2 px-6 py-4 rounded-xl bg-gold hover:bg-gold-light disabled:opacity-60 text-ink font-bold text-base transition-colors shadow-lg shadow-gold/20"
              >
                <Lock className="w-4 h-4" />
                {freeClaimLoading ? "Activating…" : "Claim Free Family Access"}
              </button>
              <p className="text-xs text-zinc-500 text-center">
                Your family access will be activated immediately.
              </p>
            </div>
          )}

          {/* Stripe payment form */}
          {clientSecret && !loading && (
            <Elements
              stripe={stripePromise}
              options={{
                clientSecret,
                appearance: {
                  theme: "night",
                  variables: {
                    colorPrimary: "#C8A96E",
                    colorBackground: "#18181b",
                    colorText: "#ffffff",
                    colorDanger: "#ef4444",
                    borderRadius: "12px",
                    fontFamily: "system-ui, sans-serif",
                  },
                },
              }}
            >
              <FamilyCheckoutForm
                cycle={cycle}
                isUpgrade={isUpgrade}
                finalPrice={displayPrice}
              />
            </Elements>
          )}
        </div>
      </div>
    </div>
  );
}

﻿"use client";

import { useEffect, useState, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { loadStripe } from "@stripe/stripe-js";
import {
  Elements,
  PaymentElement,
  useStripe,
  useElements,
} from "@stripe/react-stripe-js";
import {
  Check,
  Lock,
  Users,
  User,
  ArrowLeft,
  Shield,
  Star,
  Tag,
  X,
  Gift,
} from "lucide-react";
import Link from "next/link";
import { PLANS, formatPrice } from "@/lib/stripe-config";
import { clearCreatorPromo, getCreatorPromo } from "@/lib/creator-promos";

const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!);

type PlanChoice = "complete" | "family";

// ── Stripe payment form ───────────────────────────────────────────────────────

function CheckoutForm({
  planChoice,
  finalPrice,
}: {
  planChoice: PlanChoice;
  finalPrice: number;
}) {
  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setProcessing(true);
    setError(null);

    const { error: submitError } = await elements.submit();
    if (submitError) {
      setError(submitError.message ?? "An error occurred");
      setProcessing(false);
      return;
    }

    const returnUrl =
      planChoice === "family"
        ? `${window.location.origin}/payment/success?type=family`
        : `${window.location.origin}/payment/success`;

    const { error: confirmError } = await stripe.confirmPayment({
      elements,
      confirmParams: { return_url: returnUrl },
    });

    if (confirmError) {
      setError(confirmError.message ?? "Payment failed. Please try again.");
      setProcessing(false);
    }
  };

  const label =
    planChoice === "family"
      ? `Get Family Access — ${formatPrice(finalPrice)}`
      : `Get Lifetime Access — ${formatPrice(finalPrice)}`;

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      <PaymentElement options={{ wallets: { link: "never" } }} />

      {error && (
        <div className="p-4 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
          {error}
        </div>
      )}

      <button
        type="submit"
        disabled={!stripe || processing}
        className="w-full flex items-center justify-center gap-2 px-6 py-4 rounded-xl bg-gold hover:bg-gold-light disabled:opacity-60 text-ink font-bold text-base transition-colors shadow-lg shadow-gold/20"
      >
        <Lock className="w-4 h-4" />
        {processing ? "Processing…" : label}
      </button>

      <p className="text-xs text-zinc-500 text-center">
        Secure payment powered by Stripe · Your information is encrypted
      </p>
      <p className="text-xs text-zinc-600 text-center leading-relaxed">
        By purchasing you agree to our{" "}
        <a href="/terms" className="underline hover:text-zinc-400 transition-colors">
          Terms of Service
        </a>
        {", "}
        <a href="/privacy" className="underline hover:text-zinc-400 transition-colors">
          Privacy Policy
        </a>
        {", and "}
        <a href="/refund" className="underline hover:text-zinc-400 transition-colors">
          Refund Policy
        </a>
        .
      </p>
    </form>
  );
}

// ── Applied coupon pill ───────────────────────────────────────────────────────

interface AppliedCoupon {
  code: string;
  label: string;
  discount: number;
  finalPrice: number;
}

// ── Main checkout content ─────────────────────────────────────────────────────

interface CheckoutPageClientProps {
  userEmail?: string;
  initialPlan?: PlanChoice;
}

function CheckoutPageContent({
  userEmail = "",
  initialPlan = "complete",
}: CheckoutPageClientProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const planParam = searchParams.get("plan") as PlanChoice | null;

  const [planChoice, setPlanChoice] = useState<PlanChoice>(
    planParam === "family" ? "family" : initialPlan
  );

  // Payment intent
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Pricing (filled from API response)
  const [basePrice, setBasePrice] = useState<number>(
    planChoice === "family" ? PLANS.family.price : PLANS.complete.price
  );
  const [finalPrice, setFinalPrice] = useState<number>(basePrice);
  const [discountAmount, setDiscountAmount] = useState(0);

  // Coupon
  const [couponInput, setCouponInput] = useState("");
  const [couponLoading, setCouponLoading] = useState(false);
  const [couponError, setCouponError] = useState<string | null>(null);
  const [appliedCoupon, setAppliedCoupon] = useState<AppliedCoupon | null>(null);

  // Free access (promo code gives $0)
  const [freeAccess, setFreeAccess] = useState(false);
  const [freeClaimLoading, setFreeClaimLoading] = useState(false);
  const [freeClaimError, setFreeClaimError] = useState<string | null>(null);

  // ── Create payment intent ──────────────────────────────────────────────────

  const createIntent = async (
    plan: PlanChoice,
    promoCode?: string
  ): Promise<{ discountAmount: number; finalPrice: number } | null> => {
    setLoading(true);
    setClientSecret(null);
    setFreeAccess(false);
    setError(null);

    const endpoint =
      plan === "family"
        ? "/api/stripe/create-family-payment-intent"
        : "/api/stripe/create-payment-intent";

    try {
      const res = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ planId: "complete", promoCode }),
      });
      const data = await res.json();

      if (!res.ok) {
        if (res.status === 401) {
          router.push(
            `/signup-checkout?plan=${plan === "family" ? "family" : "complete"}`
          );
          return null;
        }
        if (res.status === 409 && (data.hasLifetime || data.hasFamily)) {
          router.push("/my-courses");
          return null;
        }
        throw new Error(data.error || "Failed to initialize checkout");
      }

      const discount: number = data.promoDiscountAmount ?? 0;
      const price: number = data.finalAmount;

      setBasePrice(data.baseAmount);
      setFinalPrice(price);
      setDiscountAmount(discount);

      if (data.freeAccess) {
        setFreeAccess(true);
      } else {
        setClientSecret(data.clientSecret);
      }
      return { discountAmount: discount, finalPrice: price };
    } catch (err) {
      setError(err instanceof Error ? err.message : "An error occurred");
      return null;
    } finally {
      setLoading(false);
    }
  };

  // ── On plan change: recreate intent (reuse applied coupon if any) ──────────

  useEffect(() => {
    // Auto-apply stored creator promo for individual plans
    if (planChoice === "complete") {
      const stored = getCreatorPromo();
      if (stored && !appliedCoupon) {
        fetch(`/api/stripe/validate-promo?code=${encodeURIComponent(stored)}`)
          .then((r) => r.json())
          .then((data) => {
            if (data.valid) {
              setAppliedCoupon({
                code: data.code,
                label: data.label,
                discount: data.promoDiscountAmount,
                finalPrice: data.finalPrice,
              });
              setCouponInput(data.code);
              return createIntent(planChoice, data.code);
            }
            clearCreatorPromo();
            return createIntent(planChoice, undefined);
          })
          .catch(() => createIntent(planChoice, undefined));
        return;
      }
    }
    createIntent(planChoice, appliedCoupon?.code);
    // Intentionally omit appliedCoupon from deps — we want the current value
    // at the time planChoice changes, not to re-run every time coupon changes.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [planChoice]);

  // ── Coupon handlers ───────────────────────────────────────────────────────

  const handleApplyCoupon = async () => {
    const code = couponInput.trim();
    if (!code) return;
    setCouponLoading(true);
    setCouponError(null);

    try {
      // For family, go straight to the intent (validate-promo uses individual base price)
      if (planChoice === "family") {
        const result = await createIntent("family", code);
        if (result) {
          setAppliedCoupon({
            code: code.toUpperCase(),
            label: "Promo applied",
            discount: result.discountAmount,
            finalPrice: result.finalPrice,
          });
        } else {
          setCouponError("Invalid promo code");
        }
        return;
      }

      // For individual, use validate-promo for a clean discount preview
      const res = await fetch(
        `/api/stripe/validate-promo?code=${encodeURIComponent(code)}`
      );
      const data = await res.json();
      if (!res.ok || !data.valid) {
        setCouponError(data.error || "Invalid promo code");
        return;
      }
      setAppliedCoupon({
        code: data.code,
        label: data.label,
        discount: data.promoDiscountAmount,
        finalPrice: data.finalPrice,
      });
      setCouponError(null);
      await createIntent("complete", data.code);
    } catch {
      setCouponError("Could not validate code. Please try again.");
    } finally {
      setCouponLoading(false);
    }
  };

  const handleRemoveCoupon = async () => {
    clearCreatorPromo();
    setAppliedCoupon(null);
    setCouponInput("");
    setCouponError(null);
    await createIntent(planChoice);
  };

  // ── Free access claim ─────────────────────────────────────────────────────

  const handleClaimFreeAccess = async () => {
    const code = appliedCoupon?.code ?? couponInput.trim();
    if (!code) return;
    setFreeClaimLoading(true);
    setFreeClaimError(null);
    try {
      const res = await fetch("/api/stripe/claim-free-access", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          promoCode: code,
          planType: planChoice === "family" ? "family" : "individual",
        }),
      });
      const data = await res.json();
      if (!res.ok) {
        setFreeClaimError(data.error || "Something went wrong");
        return;
      }
      router.push("/my-courses");
    } catch {
      setFreeClaimError("Something went wrong. Please try again.");
    } finally {
      setFreeClaimLoading(false);
    }
  };

  // ── Derived display values ────────────────────────────────────────────────

  const currentPlan = planChoice === "family" ? PLANS.family : PLANS.complete;
  const displayPrice = appliedCoupon ? appliedCoupon.finalPrice : finalPrice;
  const displayDiscount = appliedCoupon ? appliedCoupon.discount : discountAmount;
  const displayBase = appliedCoupon ? currentPlan.price : basePrice;

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col lg:flex-row">
      {/* ── Left column — plan details ─────────────────────────────────────── */}
      <div className="lg:w-1/2 bg-zinc-900/50 border-r border-zinc-800 px-6 sm:px-12 py-12 flex flex-col justify-center">
        <Link
          href="/pricing"
          className="inline-flex items-center gap-2 text-sm text-zinc-500 hover:text-zinc-300 transition-colors mb-10"
        >
          <ArrowLeft className="w-4 h-4" />
          Back to pricing
        </Link>

        <h1 className="text-3xl sm:text-4xl font-bold text-white mb-3">
          Complete Seerah
          <br />
          <span className="text-gold">Lifetime Access</span>
        </h1>

        <p className="text-zinc-400 text-base mb-8 leading-relaxed">
          One-time payment. Lifetime access to all 100 parts, every asset, every
          learner.
        </p>

        {/* Plan selector */}
        <div className="grid grid-cols-2 gap-3 mb-8">
          <button
            onClick={() => setPlanChoice("complete")}
            className={`flex flex-col p-4 rounded-xl border transition-all text-left ${
              planChoice === "complete"
                ? "border-gold/50 bg-gold/8 text-white ring-1 ring-gold/30"
                : "border-zinc-700 bg-zinc-800/50 text-zinc-400 hover:border-zinc-600"
            }`}
          >
            <div className="flex items-center gap-2 mb-2">
              <User className="w-4 h-4 flex-shrink-0" />
              <span className="font-semibold text-sm">Individual</span>
              {planChoice === "complete" && (
                <div className="ml-auto w-2 h-2 rounded-full bg-gold-light" />
              )}
            </div>
            <span className="text-2xl font-bold text-white">
              {formatPrice(PLANS.complete.price)}
            </span>
            <span className="text-xs text-zinc-500 mt-0.5">
              1 learner · one-time
            </span>
          </button>

          <button
            onClick={() => setPlanChoice("family")}
            className={`flex flex-col p-4 rounded-xl border transition-all text-left ${
              planChoice === "family"
                ? "border-gold/50 bg-gold/8 text-white ring-1 ring-gold/30"
                : "border-zinc-700 bg-zinc-800/50 text-zinc-400 hover:border-zinc-600"
            }`}
          >
            <div className="flex items-center gap-2 mb-2">
              <Users className="w-4 h-4 flex-shrink-0" />
              <span className="font-semibold text-sm">Family</span>
              {planChoice === "family" && (
                <div className="ml-auto w-2 h-2 rounded-full bg-gold-light" />
              )}
            </div>
            <span className="text-2xl font-bold text-white">
              {formatPrice(PLANS.family.price)}
            </span>
            <span className="text-xs text-zinc-500 mt-0.5">
              Up to 5 learners · one-time
            </span>
          </button>
        </div>

        {/* Feature list */}
        <ul className="space-y-3">
          {currentPlan.features.map((feature) => (
            <li key={feature} className="flex items-start gap-3">
              <div className="w-5 h-5 rounded-full bg-gold/15 flex items-center justify-center flex-shrink-0 mt-0.5">
                <Check className="w-3 h-3 text-gold" />
              </div>
              <span className="text-sm text-zinc-300">{feature}</span>
            </li>
          ))}
        </ul>

        {/* Trust badges */}
        <div className="mt-8 pt-6 border-t border-zinc-800 flex flex-wrap gap-4">
          <div className="flex items-center gap-2 text-xs text-zinc-500">
            <Shield className="w-4 h-4 text-zinc-600" />
            7-day refund guarantee
          </div>
          <div className="flex items-center gap-2 text-xs text-zinc-500">
            <Lock className="w-4 h-4 text-zinc-600" />
            Secure payment
          </div>
          <div className="flex items-center gap-2 text-xs text-zinc-500">
            <Star className="w-4 h-4 text-zinc-600" />
            Lifetime access
          </div>
        </div>
      </div>

      {/* ── Right column — order summary + payment ──────────────────────────── */}
      <div className="lg:w-1/2 px-6 sm:px-12 py-12 flex flex-col justify-center">
        <div className="max-w-md w-full mx-auto">
          <h2 className="text-xl font-bold text-white mb-1">
            Complete your order
          </h2>
          {userEmail && (
            <p className="text-sm text-zinc-500 mb-7">
              Purchasing as{" "}
              <span className="text-zinc-300">{userEmail}</span>
            </p>
          )}
          {!userEmail && <div className="mb-7" />}

          {/* Order summary card */}
          <div className="bg-zinc-900 border border-zinc-800 rounded-xl p-4 mb-6 space-y-3">
            {/* Plan row */}
            <div className="flex items-start justify-between">
              <div>
                <p className="text-sm font-semibold text-white">
                  {currentPlan.name}
                </p>
                <p className="text-xs text-zinc-500 mt-0.5">
                  {planChoice === "family"
                    ? "Up to 5 learner profiles · "
                    : ""}
                  Lifetime access
                </p>
              </div>
              <p className="text-sm font-bold text-white whitespace-nowrap ml-4">
                {formatPrice(displayBase)}
              </p>
            </div>

            {/* Discount row */}
            {displayDiscount > 0 && (
              <div className="flex items-center justify-between text-sm">
                <span className="text-green-400 flex items-center gap-1.5">
                  <Tag className="w-3.5 h-3.5" />
                  {appliedCoupon?.code ?? "Promo"} discount
                </span>
                <span className="text-green-400 font-medium">
                  −{formatPrice(displayDiscount)}
                </span>
              </div>
            )}

            {/* Total row */}
            <div className="flex items-center justify-between pt-2 border-t border-zinc-800">
              <span className="text-sm font-semibold text-white">Total</span>
              <span className="text-lg font-bold text-gold">
                {formatPrice(displayPrice)}
              </span>
            </div>
          </div>

          {/* Coupon input */}
          <div className="mb-6">
            {appliedCoupon ? (
              <div className="flex items-center justify-between px-3.5 py-2.5 rounded-xl bg-green-500/10 border border-green-500/20">
                <div className="flex items-center gap-2 text-green-400 text-sm">
                  <Tag className="w-3.5 h-3.5 flex-shrink-0" />
                  <span className="font-medium">{appliedCoupon.code}</span>
                  <span className="text-green-400/60 text-xs">
                    {appliedCoupon.label}
                  </span>
                </div>
                <button
                  onClick={handleRemoveCoupon}
                  className="text-green-400/60 hover:text-green-400 transition-colors ml-2"
                  aria-label="Remove promo code"
                >
                  <X className="w-3.5 h-3.5" />
                </button>
              </div>
            ) : (
              <div className="space-y-1.5">
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={couponInput}
                    onChange={(e) => {
                      setCouponInput(e.target.value.toUpperCase());
                      setCouponError(null);
                    }}
                    onKeyDown={(e) => e.key === "Enter" && handleApplyCoupon()}
                    placeholder="Promo code"
                    className="flex-1 px-3.5 py-2.5 text-sm rounded-xl border border-zinc-700 bg-zinc-900 text-white placeholder-zinc-500 focus:outline-none focus:border-gold/50 transition-colors uppercase"
                  />
                  <button
                    onClick={handleApplyCoupon}
                    disabled={couponLoading || !couponInput.trim()}
                    className="px-4 py-2.5 text-sm font-medium rounded-xl border border-zinc-700 bg-zinc-800 text-zinc-300 hover:border-gold/40 hover:text-gold transition-colors disabled:opacity-40 whitespace-nowrap"
                  >
                    {couponLoading ? "…" : "Apply"}
                  </button>
                </div>
                {couponError && (
                  <p className="text-xs text-red-400">{couponError}</p>
                )}
              </div>
            )}
          </div>

          {/* Loading spinner */}
          {loading && (
            <div className="flex items-center justify-center py-12">
              <div className="w-8 h-8 border-2 border-gold/30 border-t-gold rounded-full animate-spin" />
            </div>
          )}

          {/* Error state */}
          {error && !loading && (
            <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm mb-4">
              {error}
              <button
                onClick={() => window.location.reload()}
                className="block mt-2 text-red-300 underline hover:text-red-200"
              >
                Try again
              </button>
            </div>
          )}

          {/* Free access claim */}
          {freeAccess && !loading && (
            <div className="space-y-4">
              <div className="p-5 rounded-xl bg-gold/10 border border-gold/25 text-center">
                <div className="text-3xl mb-3">🎁</div>
                <h3 className="text-lg font-bold text-white mb-1">
                  Free Access Applied
                </h3>
                <p className="text-zinc-400 text-sm">
                  Your promo code gives you full{" "}
                  {planChoice === "family" ? "family " : ""}
                  access at no charge.
                </p>
              </div>
              {freeClaimError && (
                <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                  {freeClaimError}
                </div>
              )}
              <button
                onClick={handleClaimFreeAccess}
                disabled={freeClaimLoading}
                className="w-full flex items-center justify-center gap-2 px-6 py-4 rounded-xl bg-gold hover:bg-gold-light disabled:opacity-60 text-ink font-bold text-base transition-colors shadow-lg shadow-gold/20"
              >
                <Lock className="w-4 h-4" />
                {freeClaimLoading ? "Activating…" : "Claim Free Access"}
              </button>
              <p className="text-xs text-zinc-500 text-center">
                Your access will be activated immediately.
              </p>
            </div>
          )}

          {/* Stripe payment form */}
          {clientSecret && !loading && (
            <Elements
              stripe={stripePromise}
              options={{
                clientSecret,
                appearance: {
                  theme: "night",
                  variables: {
                    colorPrimary: "#C8A96E",
                    colorBackground: "#18181b",
                    colorText: "#ffffff",
                    colorDanger: "#ef4444",
                    borderRadius: "12px",
                    fontFamily: "system-ui, sans-serif",
                  },
                },
              }}
            >
              <CheckoutForm planChoice={planChoice} finalPrice={displayPrice} />
            </Elements>
          )}

          {/* Gift link */}
          {!freeAccess && !loading && planChoice === "complete" && (
            <div className="mt-6 pt-5 border-t border-zinc-800 text-center">
              <p className="text-xs text-zinc-600 mb-1">
                Buying for someone else?
              </p>
              <a
                href="/gift-checkout"
                className="inline-flex items-center gap-1.5 text-xs text-gold/70 hover:text-gold transition-colors font-medium"
              >
                <Gift className="w-3.5 h-3.5" />
                Gift Lifetime Access instead →
              </a>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

