"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import { Gift, Check, Mail, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";

interface GiftSentState {
  loading: boolean;
  error: string | null;
  recipientEmail: string | null;
  recipientName: string | null;
}

function GiftSentContent() {
  const searchParams = useSearchParams();
  const paymentIntent = searchParams.get("payment_intent");

  const [state, setState] = useState<GiftSentState>({
    loading: true,
    error: null,
    recipientEmail: null,
    recipientName: null,
  });

  useEffect(() => {
    if (!paymentIntent) {
      setState({ loading: false, error: "No payment information found.", recipientEmail: null, recipientName: null });
      return;
    }

    async function verifyGift() {
      try {
        const res = await fetch(`/api/gift/verify-and-create?payment_intent=${paymentIntent}`);
        const data = await res.json();
        if (!res.ok) {
          setState({ loading: false, error: data.error ?? "Failed to verify gift payment.", recipientEmail: null, recipientName: null });
          return;
        }
        setState({
          loading: false,
          error: null,
          recipientEmail: data.recipientEmail,
          recipientName: data.recipientName,
        });
      } catch {
        setState({ loading: false, error: "Something went wrong verifying your payment.", recipientEmail: null, recipientName: null });
      }
    }

    verifyGift();
  }, [paymentIntent]);

  if (state.loading) {
    return (
      <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
        <div className="text-center">
          <div className="w-16 h-16 border-2 border-gold border-t-transparent rounded-full animate-spin mx-auto mb-4" />
          <p className="text-text-secondary">Sending your gift…</p>
        </div>
      </div>
    );
  }

  if (state.error) {
    return (
      <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
        <div className="max-w-md w-full bg-surface border border-border rounded-2xl p-8 text-center">
          <div className="w-16 h-16 mx-auto rounded-full bg-red-500/10 border border-red-500/30 flex items-center justify-center mb-4">
            <span className="text-2xl">✕</span>
          </div>
          <h1 className="text-2xl font-bold mb-2">Something Went Wrong</h1>
          <p className="text-text-secondary mb-6">{state.error}</p>
          <div className="space-y-3">
            <Link href="/contact">
              <Button variant="primary" size="lg" className="w-full justify-center">Contact Support</Button>
            </Link>
            <Link href="/">
              <Button variant="ghost" size="md" className="w-full justify-center">Back to Home</Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
      <div className="max-w-lg w-full">

        {/* Success header */}
        <div className="text-center mb-8">
          <div className="w-20 h-20 mx-auto rounded-full bg-gold/10 border-2 border-gold/40 flex items-center justify-center mb-6 relative">
            <Gift className="w-10 h-10 text-gold" />
            <div className="absolute inset-0 rounded-full bg-gold/10 animate-ping" />
          </div>
          <h1 className="text-3xl sm:text-4xl font-bold mb-3">Your Gift Has Been Sent!</h1>
          <p className="text-lg text-text-secondary">
            JazakAllahu Khayran for your generosity.
          </p>
        </div>

        {/* Details card */}
        <div className="bg-surface border border-border rounded-2xl p-6 sm:p-8 space-y-5">

          <div className="space-y-3">
            <div className="flex items-start gap-3">
              <div className="w-8 h-8 rounded-full bg-gold/10 border border-gold/25 flex items-center justify-center flex-shrink-0 mt-0.5">
                <Check className="w-4 h-4 text-gold" />
              </div>
              <div>
                <p className="text-text font-medium">Payment confirmed</p>
                <p className="text-text-secondary text-sm">Lifetime access purchased successfully</p>
              </div>
            </div>

            <div className="flex items-start gap-3">
              <div className="w-8 h-8 rounded-full bg-gold/10 border border-gold/25 flex items-center justify-center flex-shrink-0 mt-0.5">
                <Mail className="w-4 h-4 text-gold" />
              </div>
              <div>
                <p className="text-text font-medium">Gift email sent</p>
                <p className="text-text-secondary text-sm">
                  {state.recipientName
                    ? `${state.recipientName} (${state.recipientEmail})`
                    : state.recipientEmail}{" "}
                  will receive a claim link to activate their access.
                </p>
              </div>
            </div>

            <div className="flex items-start gap-3">
              <div className="w-8 h-8 rounded-full bg-gold/10 border border-gold/25 flex items-center justify-center flex-shrink-0 mt-0.5">
                <Check className="w-4 h-4 text-gold" />
              </div>
              <p className="text-text-secondary">
                They&apos;ll create a free account (or sign in) to claim their access instantly
              </p>
            </div>
          </div>

          <div className="p-4 rounded-xl bg-gold/5 border border-gold/15">
            <p className="text-sm text-text-secondary leading-relaxed">
              <strong className="text-text">Heads up:</strong> If your recipient doesn&apos;t see the email within a few minutes, ask them to check their spam folder.
              The subject line is: <em className="text-gold">&quot;You&apos;ve been gifted Complete Seerah&quot;</em>
            </p>
          </div>

          <div className="pt-4 border-t border-border">
            <Link href="/seerah">
              <Button variant="ghost" size="lg" className="w-full justify-center gap-2">
                Go to Your Dashboard
                <ArrowRight className="w-4 h-4" />
              </Button>
            </Link>
          </div>
        </div>

        <p className="text-center text-sm text-text-muted mt-6">
          Questions?{" "}
          <Link href="/contact" className="text-gold hover:text-gold-light">Contact support</Link>
        </p>
      </div>
    </div>
  );
}

export default function GiftSentPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
          <div className="text-center">
            <div className="w-16 h-16 border-2 border-gold border-t-transparent rounded-full animate-spin mx-auto mb-4" />
            <p className="text-text-secondary">Loading…</p>
          </div>
        </div>
      }
    >
      <GiftSentContent />
    </Suspense>
  );
}

"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import { Check, ArrowRight, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";

type SuccessType = "lifetime" | "subscription" | "family" | "family-subscription";

const MAX_POLL_MS = 20_000;
const POLL_INTERVAL_MS = 2_000;

function PaymentSuccessPageContent() {
  const searchParams = useSearchParams();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [successType, setSuccessType] = useState<SuccessType>("lifetime");

  const paymentIntent = searchParams.get("payment_intent");
  const type = searchParams.get("type"); // "subscription" | "family" | null
  const preview = searchParams.get("preview"); // dev-only: bypass payment verification

  useEffect(() => {
    // Dev preview mode — skip all verification, show the success screen directly.
    // Explicitly disabled in production so no one can bypass payment verification.
    if (preview === "1" && process.env.NODE_ENV !== "production") {
      setSuccessType(
        type === "family" ? "family" :
        type === "family-subscription" ? "family-subscription" :
        type === "subscription" ? "subscription" :
        "lifetime"
      );
      setLoading(false);
      return;
    }

    // Subscription payment (individual monthly or family monthly) —
    // poll until webhook confirms access (up to MAX_POLL_MS).
    if (type === "subscription" || type === "family-subscription") {
      setSuccessType(type === "family-subscription" ? "family-subscription" : "subscription");

      const start = Date.now();

      async function pollAccess() {
        try {
          const res = await fetch("/api/stripe/check-access");
          if (res.status === 401) {
            // User somehow logged out — show generic success without crashing
            setLoading(false);
            return;
          }
          if (res.ok) {
            const data = await res.json();
            if (data.hasAccess) {
              setLoading(false);
              return;
            }
          }
        } catch {
          // Network error — keep polling
        }

        if (Date.now() - start >= MAX_POLL_MS) {
          // Timed out waiting for webhook — show a softer message
          setError(
            "Payment received. We're finishing setup — this usually takes a few seconds. " +
              "Refresh the page or go to the dashboard. If access is missing, contact support."
          );
          setLoading(false);
          return;
        }

        setTimeout(pollAccess, POLL_INTERVAL_MS);
      }

      pollAccess();
      return;
    }

    // One-time payment (Individual Lifetime or Family Lifetime) —
    // verify the PaymentIntent then show the appropriate success screen.
    async function verifyPayment() {
      if (!paymentIntent) {
        setError("No payment information found");
        setLoading(false);
        return;
      }
      try {
        const response = await fetch(
          `/api/stripe/verify-payment?payment_intent=${paymentIntent}`
        );
        if (!response.ok) throw new Error("Payment verification failed");
        setSuccessType(type === "family" ? "family" : "lifetime");
        setLoading(false);
      } catch {
        setError("Failed to verify payment. If you were charged, contact support.");
        setLoading(false);
      }
    }

    verifyPayment();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (loading) {
    // Both individual monthly ("subscription") and family monthly ("family-subscription")
    // use polling — show subscription copy for both. One-time payments show payment copy.
    const isAnySubscription = type === "subscription" || type === "family-subscription";
    return (
      <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
        <div className="text-center">
          <div className="w-16 h-16 border-2 border-gold border-t-transparent rounded-full animate-spin mx-auto mb-4" />
          <p className="text-text-secondary">
            {isAnySubscription
              ? "Confirming your subscription…"
              : "Verifying your payment…"}
          </p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
        <div className="max-w-md w-full bg-surface border border-border rounded-2xl p-8 text-center">
          <div className="w-16 h-16 mx-auto rounded-full bg-amber-500/10 border border-amber-500/30 flex items-center justify-center mb-4">
            <RefreshCw className="w-7 h-7 text-amber-400" />
          </div>
          <h1 className="text-xl font-bold mb-2">Almost there…</h1>
          <p className="text-text-secondary mb-6 text-sm leading-relaxed">{error}</p>
          <div className="space-y-3">
            <Link href="/my-courses">
              <Button variant="primary" size="lg" className="w-full">
                Go to Dashboard
              </Button>
            </Link>
            <Link href="/contact">
              <Button variant="ghost" size="md" className="w-full">
                Contact Support
              </Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  const isSubscription      = successType === "subscription";        // individual monthly
  const isFamilySubscription = successType === "family-subscription"; // family monthly
  const isFamily             = successType === "family";              // family lifetime
  const isFamilyAny          = isFamily || isFamilySubscription;      // any family plan

  return (
    <div className="min-h-screen bg-ink text-text flex items-center justify-center px-4">
