            </Link>
          </div>
        </div>

        <p className="text-center text-sm text-text-muted mt-6">
          Questions?{" "}
          <Link href="/contact" className="text-gold hover:text-gold-light">
            Contact support
          </Link>
        </p>
      </div>
    </div>
  );
}

