// ─── Mode button ──────────────────────────────────────────────────────────────

function ModeButton({
  mode,
  isActive,
  isAvailable,
  isLocked,
  onClick,
}: {
  mode: Mode;
  isActive: boolean;
  isAvailable: boolean;
  isLocked: boolean;
  onClick: () => void;
}) {
  const Icon = mode.icon;
  const isPrimary = !!mode.primary;
  const isDisabled = !isAvailable && !isLocked;

  return (
    <button
      onClick={onClick}
      disabled={isDisabled}
      aria-disabled={isDisabled ? "true" : undefined}
      aria-pressed={isActive}
      className={clsx(
        "relative flex flex-col items-center justify-center flex-1 lg:flex-none lg:max-w-[150px] 2xl:max-w-[160px] rounded-xl border",
        "transition-all duration-200 active:scale-[0.96]",
        "min-h-[52px] sm:min-h-[56px]",
        isPrimary
          ? "px-1.5 sm:px-4 py-2.5 sm:py-3 gap-0.5"
          : "px-1 sm:px-3 py-2 sm:py-2.5 gap-0.5",
        // Active — softer gold so media stays dominant
        isActive
          ? "border-gold/30 bg-gold/8 text-gold shadow-sm shadow-gold/10"
          : isDisabled
          ? "border-border/15 bg-surface/20 text-text-muted/25 cursor-not-allowed pointer-events-none"
          : isAvailable
          ? isPrimary
            // Primary inactive — clearer, more prominent
            ? "border-border/60 bg-surface-raised/70 text-text-secondary hover:border-gold/20 hover:bg-surface-high hover:text-text cursor-pointer"
            // Secondary inactive — brighter than before, still quieter than primary
            : "border-border/50 bg-surface-raised/50 text-text-secondary/75 hover:border-border/70 hover:bg-surface-raised hover:text-text-secondary cursor-pointer"
          : "border-border/30 bg-surface/40 text-text-muted/60 hover:border-gold/15 hover:bg-surface-raised/50 cursor-pointer"
      )}
    >
      {/* Icon */}
      <Icon className={clsx(
        "flex-shrink-0 transition-all duration-200",
        isPrimary ? "w-4 h-4" : "w-3.5 h-3.5",
        isActive ? "opacity-100" : isDisabled ? "opacity-20" : isPrimary ? "opacity-65" : "opacity-75"
      )} />

      {/* Label — use shortLabel on narrow screens when available */}
      <span className={clsx(
        "truncate leading-none font-semibold",
        isPrimary ? "text-[11px] sm:text-[13px]" : "text-[10px] sm:text-xs",
        isActive ? "opacity-100" : isDisabled ? "opacity-25" : "opacity-90"
      )}>
        {mode.shortLabel ? (
          <>
            <span className="min-[360px]:hidden">{mode.shortLabel}</span>
            <span className="hidden min-[360px]:inline">{mode.label}</span>
          </>
        ) : mode.label}
      </span>

      {/* Subtitle — primary on mobile, all on desktop */}
      <span className={clsx(
        "leading-none truncate",
        isPrimary ? "text-[9px] sm:text-[10px]" : "hidden sm:block text-[9px]",
        isActive ? "text-gold/55" : isDisabled ? "opacity-20" : isPrimary ? "text-text-muted/40" : "text-text-muted/55",
      )}>
        {mode.subtitle}
      </span>

      {/* Active underline accent */}
      {isActive && (
        <span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-8 h-[2px] bg-gold/60 rounded-full" />
      )}
    </button>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

interface PartTabsProps {
  part: Part;
  userPlan: UserPlan;
  previewMode?: boolean;
  initialAssetUrls?: PartAssetUrls;
}

export function PartTabs({ part, userPlan: _userPlan, previewMode = false, initialAssetUrls }: PartTabsProps) {
  const availableModes = MODES.filter((m) => getModeSubTabs(m, part).length > 0);
  const defaultMode = availableModes[0] ?? MODES[0];

  const searchParams = useSearchParams();
  const router = useRouter();

  // View mode toggle: "focus" = tab layout, "gallery" = all assets inline
  // Priority: URL param > localStorage > "focus"
  const VIEW_STORAGE_KEY = "seerah:lessonViewMode";
  const viewParam = searchParams.get("view") as ViewMode | null;
  const [viewMode, setViewMode] = useState<ViewMode>(
    viewParam === "gallery" ? "gallery" : "focus"
  );

  useEffect(() => {
    if (viewParam) return;
    try {
      const stored = localStorage.getItem(VIEW_STORAGE_KEY) as ViewMode | null;
      if (stored === "gallery" || stored === "focus") setViewMode(stored);
    } catch {}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleViewToggle = useCallback((mode: ViewMode) => {
    setViewMode(mode);
    try { localStorage.setItem(VIEW_STORAGE_KEY, mode); } catch {}
    const params = new URLSearchParams(searchParams.toString());
    if (mode === "gallery") {
      params.set("view", "gallery");
    } else {
      params.delete("view");
    }
    router.replace(`?${params.toString()}`, { scroll: false });
  }, [searchParams, router]);

  // Initialise from ?mode= URL param so deep links and browser back/fwd work
  const modeParam = searchParams.get("mode") as ModeId | null;
  const resolvedInitialMode: ModeId =
    modeParam && availableModes.some((m) => m.id === modeParam) ? modeParam : defaultMode.id;

  const [activeMode, setActiveMode] = useState<ModeId>(resolvedInitialMode);
  const currentMode = MODES.find((m) => m.id === activeMode) ?? defaultMode;
  const subTabs = getModeSubTabs(currentMode, part);

  const [activeSubTab, setActiveSubTab] = useState<SubTabId>(subTabs[0]?.id ?? "video");

  // Sync state when browser navigates (back/forward)
  useEffect(() => {
    const incoming = modeParam && availableModes.some((m) => m.id === modeParam) ? modeParam : defaultMode.id;
    if (incoming !== activeMode) {
      setActiveMode(incoming);
      const newSubTabs = getModeSubTabs(MODES.find((m) => m.id === incoming)!, part);
      setActiveSubTab(newSubTabs[0]?.id ?? MODES.find((m) => m.id === incoming)!.subTabs[0].id as SubTabId);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [modeParam]);

  // Use server-provided URLs immediately; fall back to client-side fetch only if not provided
  const [assetUrls, setAssetUrls] = useState<PartAssetUrls>(initialAssetUrls ?? {});
  useEffect(() => {
    if (initialAssetUrls?.videoUrl || initialAssetUrls?.audioUrl || initialAssetUrls?.mindmapUrl) return;
    fetchPartAssets(part.partNumber).then(setAssetUrls);
  }, [part.partNumber, initialAssetUrls]);

  // Track which panels have been rendered at least once — never unmount after first visit
  const [renderedPanels, setRenderedPanels] = useState<Set<string>>(
    () => new Set([`${resolvedInitialMode}::${getModeSubTabs(MODES.find((m) => m.id === resolvedInitialMode)!, part)[0]?.id ?? MODES.find((m) => m.id === resolvedInitialMode)!.subTabs[0].id}`])
  );

  const handleModeChange = useCallback((modeId: ModeId) => {
    setActiveMode(modeId);
    const newSubTabs = getModeSubTabs(MODES.find((m) => m.id === modeId)!, part);
    const newSubTabId = newSubTabs[0]?.id ?? MODES.find((m) => m.id === modeId)!.subTabs[0].id;
    setActiveSubTab(newSubTabId as SubTabId);
    setRenderedPanels((prev) => new Set([...prev, `${modeId}::${newSubTabId}`]));
    // Persist in URL without full navigation
    const params = new URLSearchParams(searchParams.toString());
    params.set("mode", modeId);
    router.replace(`?${params.toString()}`, { scroll: false });
  }, [part, searchParams, router]);

  const handleSubTabChange = (tabId: SubTabId) => {
    setActiveSubTab(tabId);
    setRenderedPanels((prev) => new Set([...prev, `${activeMode}::${tabId}`]));
  };


  const currentSubTab = subTabs.find((t) => t.id === activeSubTab)?.id ?? subTabs[0]?.id;

  // All panels that should ever be rendered (visited at least once)
  const allPanels = [...renderedPanels];

  return (
    <div className="space-y-5">

      {/* ── View toggle header (hidden in preview/homepage) ──────────────── */}
      {!previewMode && (
        <div className="flex items-center justify-between gap-4">
          <p className="text-[10px] font-bold uppercase tracking-[0.12em] text-text-muted/35">
            {viewMode === "gallery" ? "All Assets" : "Learning Mode"}
          </p>
          <LessonViewToggle viewMode={viewMode} onToggle={handleViewToggle} />
        </div>
      )}

      {/* ── Gallery view ─────────────────────────────────────────────────── */}
      {!previewMode && viewMode === "gallery" && (
        <LessonGalleryView
          part={part}
          assetUrls={assetUrls}
          previewMode={previewMode}
        />
      )}

      {/* ── Focus view — existing tab layout ─────────────────────────────── */}
      {(previewMode || viewMode === "focus") && (
        <div className="space-y-6">

          {/* Mode selector strip */}
          <div className="space-y-1.5 sm:space-y-0">
            {/* Mobile: two rows — primary (Watch/Read/Slides) then secondary */}
            {/* Desktop: single row with all tabs */}
            <div className="sm:hidden space-y-2">
              {/* LEARN group */}
              <div className="space-y-1">
                <p className="text-[10px] font-bold uppercase tracking-[0.12em] text-text-muted/35 px-0.5">Learn</p>
                <div className="flex gap-1.5">
                  {MODES.filter((m) => m.primary).map((mode) => {
                    const available = getModeSubTabs(mode, part).length > 0;
                    return (
                      <ModeButton
                        key={mode.id}
                        mode={mode}
                        isActive={activeMode === mode.id}
                        isAvailable={available}
                        isLocked={false}
                        onClick={() => available ? handleModeChange(mode.id) : undefined}
                      />
                    );
                  })}
                </div>
              </div>
              {/* REVIEW group */}
              <div className="space-y-1">
                <p className="text-[10px] font-bold uppercase tracking-[0.12em] text-text-muted/35 px-0.5">Review</p>
                <div className="flex gap-1">
                  {MODES.filter((m) => !m.primary).map((mode) => {
                    const available = getModeSubTabs(mode, part).length > 0;
                    return (
                      <ModeButton
                        key={mode.id}
                        mode={mode}
                        isActive={activeMode === mode.id}
                        isAvailable={available}
                        isLocked={false}
                        onClick={() => available ? handleModeChange(mode.id) : undefined}
                      />
                    );
                  })}
                </div>
              </div>
            </div>
            {/* Desktop: all in one row — lg:justify-center prevents giant buttons at ultrawide */}
            <div className="hidden sm:flex gap-2 lg:justify-center lg:flex-wrap">
              {MODES.map((mode) => {
                const available = getModeSubTabs(mode, part).length > 0;
                return (
                  <ModeButton
                    key={mode.id}
                    mode={mode}
                    isActive={activeMode === mode.id}
                    isAvailable={available}
                    isLocked={false}
                    onClick={() => available ? handleModeChange(mode.id) : undefined}
                  />
                );
              })}
              <TimelineButton partNumber={part.partNumber} era={part.era} previewMode={previewMode} />
            </div>
          </div>

          {/* Sub-tab bar (only when mode has multiple content items) */}
          {subTabs.length > 1 && (
            <div className="flex gap-1.5 overflow-x-auto scrollbar-hide">
              {subTabs.map((tab) => {
                const Icon = tab.icon;
                const isActive = currentSubTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => handleSubTabChange(tab.id)}
                    className={clsx(
                      "flex items-center gap-1.5 px-3 rounded-lg text-xs font-medium",
                      "transition-all duration-150 active:scale-95 flex-shrink-0 whitespace-nowrap",
                      "min-h-[44px]",
                      isActive
                        ? "bg-gold/12 text-gold ring-1 ring-gold/20"
                        : "bg-surface-raised/50 text-text-muted/75 hover:text-text-secondary hover:bg-surface-raised"
                    )}
                  >
                    <Icon className={clsx("w-3 h-3 transition-opacity", isActive ? "opacity-100" : "opacity-55")} />
                    {tab.label}
                  </button>
                );
              })}
            </div>
          )}

          {/* Content — panels stay mounted after first visit, hidden via CSS */}
          <div className="pt-0.5">
            {allPanels.map((panelKey) => {
              const [modeId, subTabId] = panelKey.split("::");
              const isVisible = activeMode === modeId && currentSubTab === subTabId;
              return (
                <div
                  key={panelKey}
                  className={isVisible ? "animate-in fade-in-0 duration-200" : "hidden"}
                >
                  <SubTabContent
                    id={subTabId as SubTabId}
                    part={part}
                    previewMode={previewMode}
                    assetUrls={assetUrls}
                    onSwitchMode={handleModeChange}
                  />
                </div>
              );
            })}
          </div>

        </div>
      )}

    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { ChevronLeft, ChevronRight, Layers, Maximize2, X } from "lucide-react";
import { trackAssetOpened } from "@/app/actions/progress";
import type { SlideFile } from "@/lib/types";

/** Main slide image. Shows a spinner while loading, re-triggers on src change. */
function SlideImg({ src, alt, priority }: { src: string; alt: string; priority?: boolean }) {
  const [loaded, setLoaded] = useState(false);

  useEffect(() => { setLoaded(false); }, [src]);

  return (
    <>
      {!loaded && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-8 h-8 border-2 border-gold/30 border-t-gold rounded-full animate-spin" />
        </div>
      )}
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={src}
        alt={alt}

        fetchPriority={priority ? "high" : "auto"}
        className={`max-w-full max-h-full object-contain transition-opacity duration-200 ${loaded ? "opacity-100" : "opacity-0"}`}
        onLoad={() => setLoaded(true)}
      />
    </>
  );
}

interface SlidesViewerProps {
  slides: SlideFile[];
  title?: string;
  type?: "presented" | "detailed";
  partNumber?: number;
  previewMode?: boolean;
}

export function SlidesViewer({ slides, title, type = "presented", partNumber, previewMode }: SlidesViewerProps) {
  const [current, setCurrent] = useState(0);
  const [fullscreen, setFullscreen] = useState(false);
  const stripRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const touchStartX = useRef<number | null>(null);

  const prev = useCallback(() => setCurrent((c) => Math.max(0, c - 1)), []);
  const next = useCallback(
    () => setCurrent((c) => Math.min(slides.length - 1, c + 1)),
    [slides.length]
  );

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  }, []);

  const handleTouchEnd = useCallback((e: React.TouchEvent) => {
    if (touchStartX.current === null) return;
    const delta = e.changedTouches[0].clientX - touchStartX.current;
    touchStartX.current = null;
    if (Math.abs(delta) < 50) return; // ignore small taps
    if (delta < 0) next(); else prev();
  }, [next, prev]);

  useEffect(() => {
    // Keep CSS state in sync when native fullscreen is toggled (e.g. Esc key)
    const handler = () => {
      if (!document.fullscreenElement) setFullscreen(false);
    };
    document.addEventListener("fullscreenchange", handler);
    return () => document.removeEventListener("fullscreenchange", handler);
  }, []);

  const enterFullscreen = useCallback(async () => {
    // Set CSS overlay immediately — reliable across all browsers
    setFullscreen(true);
    // Also attempt native fullscreen as an enhancement (browser chrome disappears)
    if (containerRef.current?.requestFullscreen) {
      try {
        await containerRef.current.requestFullscreen();
      } catch {
        // Native fullscreen denied — CSS overlay is already shown, nothing to do
      }
    }
  }, []);

  const exitFullscreenMode = useCallback(() => {
    setFullscreen(false);
    if (document.fullscreenElement) {
      document.exitFullscreen().catch(() => {});
    }
  }, []);

  useEffect(() => {
    if (!partNumber || previewMode || !slides.length) return;
    trackAssetOpened(partNumber, "slides").catch(() => {});
    window.dispatchEvent(new CustomEvent("seerah:progressUpdate", { detail: { openedAssets: ["slides"] } }));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const strip = stripRef.current;
    if (!strip) return;
    const thumb = strip.querySelectorAll("button")[current] as HTMLElement | undefined;
    thumb?.scrollIntoView({ behavior: "auto", block: "nearest", inline: "nearest" });
  }, [current]);

  useEffect(() => {
    if (!fullscreen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "ArrowLeft") prev();
      if (e.key === "ArrowRight") next();
      if (e.key === "Escape") exitFullscreenMode();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [fullscreen, prev, next, exitFullscreenMode]);

  if (!slides.length) {
    return (
      <div className="aspect-video rounded-2xl border border-border bg-surface flex flex-col items-center justify-center gap-3">
        <div className="w-14 h-14 rounded-xl bg-gold/10 border border-gold/20 flex items-center justify-center">
          <Layers className="w-6 h-6 text-gold/50" />
        </div>
        <div className="text-center">
          <p className="text-text-secondary text-sm font-medium">No slides for this part</p>
          <p className="text-xs text-text-muted mt-1">
            {type === "presented" ? "Presented" : "Detailed"} slides will be available shortly
          </p>
        </div>
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className={
        fullscreen
          ? "fixed inset-0 z-50 bg-black flex flex-col"
          : "rounded-2xl border border-border overflow-hidden bg-black flex flex-col"
      }
    >
      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-3 bg-ink/80 border-b border-border/50 flex-shrink-0">
        <Layers className="w-4 h-4 text-gold flex-shrink-0" />
        <p className="text-sm text-text-secondary flex-1 truncate">
          {title || (type === "presented" ? "Presented Slides" : "Detailed Slides")}
        </p>
        <span className="text-xs text-text-muted tabular-nums">
          {current + 1} / {slides.length}
        </span>
        <button
          onClick={() => fullscreen ? exitFullscreenMode() : enterFullscreen()}
          className="min-h-[44px] min-w-[44px] flex items-center justify-center text-text-muted hover:text-text transition-colors -mr-2"
          aria-label={fullscreen ? "Exit fullscreen" : "Enter fullscreen"}
        >
          {fullscreen ? <X className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
        </button>
      </div>

      {/* Slide area — swipe left/right to navigate on mobile */}
      <div
        className={`relative flex-1 bg-black ${!fullscreen ? "group cursor-zoom-in" : ""}`}
        style={{ minHeight: fullscreen ? undefined : "min(420px, 55vw)" }}
        onClick={!fullscreen ? () => enterFullscreen() : undefined}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
        title={!fullscreen ? "Tap for fullscreen · Swipe to navigate" : undefined}
      >
        {/* Render current ±2 slides; hidden ones are pre-loaded but invisible */}
        {slides.map((slide, idx) => {
          const distance = Math.abs(idx - current);
          if (distance > 2) return null;
          return (
            <div
              key={idx}
              className="absolute inset-0 flex items-center justify-center transition-opacity duration-150"
              style={{
                opacity: idx === current ? 1 : 0,
                pointerEvents: idx === current ? "auto" : "none",
                zIndex: idx === current ? 1 : 0,
              }}
            >
              <SlideImg src={slide.medium} alt={`Slide ${idx + 1}`} priority={idx === current} />
            </div>
          );
        })}

        {/* Fullscreen hint — always visible at low opacity on mobile */}
        {!fullscreen && (
          <div className="absolute bottom-2 left-1/2 -translate-x-1/2 pointer-events-none">
            <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-black/60 border border-white/10 text-white/50 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity text-[10px] font-medium">
              <Maximize2 className="w-3 h-3" />
              <span>Tap · Swipe to navigate</span>
            </div>
          </div>
        )}

        {/* Prev — 44px */}
        <button
          onClick={(e) => { e.stopPropagation(); prev(); }}
          disabled={current === 0}
          className="absolute left-2 top-1/2 -translate-y-1/2 z-10 min-w-[44px] min-h-[44px] rounded-full bg-black/60 border border-white/15 flex items-center justify-center text-white/70 hover:text-white hover:border-white/40 disabled:opacity-20 transition-all"
          aria-label="Previous slide"
        >
          <ChevronLeft className="w-5 h-5" />
        </button>
        {/* Next — 44px */}
        <button
          onClick={(e) => { e.stopPropagation(); next(); }}
          disabled={current === slides.length - 1}
          className="absolute right-2 top-1/2 -translate-y-1/2 z-10 min-w-[44px] min-h-[44px] rounded-full bg-black/60 border border-white/15 flex items-center justify-center text-white/70 hover:text-white hover:border-white/40 disabled:opacity-20 transition-all"
          aria-label="Next slide"
        >
          <ChevronRight className="w-5 h-5" />
        </button>
      </div>

      {/* Thumbnail strip — fade hint at right edge indicates more content */}
      {slides.length > 1 && (
        <div className="relative bg-ink/80 border-t border-border/50 flex-shrink-0">
          {/* Fade overlay at right edge */}
          <div className="pointer-events-none absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-ink/80 to-transparent z-10" aria-hidden />
        <div ref={stripRef} className="pl-4 py-3 flex gap-2 overflow-x-auto no-scrollbar">
          {slides.map((slide, i) => (
            <button
              key={i}
              onClick={() => setCurrent(i)}
              aria-label={`Go to slide ${i + 1}`}
              aria-current={i === current ? "true" : undefined}
              className={`flex-shrink-0 w-20 h-11 rounded border overflow-hidden transition-all ${
                i === current
                  ? "border-gold ring-1 ring-gold/30"
                  : "border-border/50 opacity-50 hover:opacity-100"
              }`}
            >
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img src={slide.thumb} alt={`Slide ${i + 1}`} className="w-full h-full object-cover" />
            </button>
          ))}
          <div className="flex-shrink-0 w-8" aria-hidden />
        </div>
        </div>
      )}
    </div>
  );
}

